def a(n):
    # Each card: [id, face] where face 1=up, 0=down
    deck = [[i, 1] for i in range(n)]
    steps = 0
    while True:
        for k in range(1, n + 1):
            packet = deck[:k]
            packet.reverse()
            for card in packet:
                card[1] = 1 - card[1]
            deck = packet + deck[k:]
            steps += 1
            if all(deck[i][0] == i and deck[i][1] == 1 for i in range(n)):
                return steps
print([a(n) for n in range(1, 21)])

